const v13ReadA={id:"v13-read-a",kind:"passage",label:"Passage for Items 69-72",title:"Flood Message Test",description:"A riverside town sent flood warnings through text messages, radio announcements, and vehicle-mounted speakers. After one storm, a survey found that most residents received at least one warning, but several could not tell whether the message was an advisory or an immediate evacuation order. The town rewrote the messages using three fixed levels, a plain-language action for each level, and the time of the next update. In a tabletop exercise, participants identified the required action more accurately. Officials still planned a nighttime drill because the exercise did not test power interruptions, sleeping households, or road access during actual rain.",alt:"Passage about a town improving flood warnings with fixed levels and explicit actions, then planning a nighttime drill to test conditions not covered by a tabletop exercise."};
const v13ReadB={id:"v13-read-b",kind:"passage",label:"Babasahin para sa Aytem 73-76",title:"Sulok-Basahan sa Terminal",description:"Nagtayo ang pamunuan ng terminal ng maliit na sulok-basahan para sa mga pasaherong naghihintay. Maraming aklat ang naibigay, ngunit iilan lamang ang humihiram dahil nasa likod ng ticket booth ang estante at hindi pansin mula sa upuan. Inilipat ang estante sa maliwanag na bahagi, naglagay ng malinaw na karatula, at gumamit ng payak na talaan ng hiram at balik. Dumami ang gumagamit, subalit may mga aklat na hindi naibabalik sa tamang lalagyan. Sa susunod na buwan, susubukan ang mga kahong may kulay at larawan ayon sa uri ng babasahin.",alt:"Teksto tungkol sa sulok-basahan sa terminal na inilipat sa mas lantad na lugar, ginamitan ng payak na talaan, at lalagyan ng mga kahong may kulay at larawan upang maayos ang pagbabalik."};
const v13ReadC={id:"v13-read-c",kind:"passage",label:"Passage for Items 77-80",title:"Publishing Procurement Data",description:"A provincial office began publishing bid notices, award decisions, and contract milestones in one online register. The register reduced calls asking where documents could be found, but users reported that project names changed between the notice and contract stages. The office created a permanent project identifier and required every update to use it. Search accuracy improved, yet the office postponed publishing supplier contact details until a privacy and security review was completed. The next review would examine whether records were timely, complete, and understandable, not merely whether a file had been uploaded.",alt:"Passage about a procurement register, permanent project identifiers that improved search, withholding supplier contacts pending review, and evaluating timeliness, completeness, and clarity."};
const v13DataA={id:"v13-data-a",kind:"table",label:"Table for Items 155-158",title:"Immunization Outreach",description:"People scheduled, served, receiving a second dose, and absent at four sites. Unit: people.",headers:["Site","Scheduled","Served","Second dose","Absent"],rows:[["Central",110,102,64,8],["Hill",95,88,55,7],["Lakeside",120,108,72,12],["Riverside",80,76,46,4]],legend:["Served plus absent equals scheduled","Second dose is a subset of served"],alt:"Central: 110 scheduled, 102 served, 64 second dose, 8 absent. Hill: 95, 88, 55, 7. Lakeside: 120, 108, 72, 12. Riverside: 80, 76, 46, 4."};
